const items = $input.all();
const transactions = items.map(i => i.json);

// ── 1. Fingerprint-based duplicate detection ──────────────────────
const seen = new Map();
const duplicatesMap = new Map(); // easier lookup per transaction

transactions.forEach(tx => {
  const fingerprint = `${tx.vendor}|${tx.amount}|${tx.date}|${tx.employee}`;

  if (seen.has(fingerprint)) {
    const originalId = seen.get(fingerprint);

    duplicatesMap.set(tx.transaction_id, {
      is_duplicate: true,
      original_id: originalId,
      reason: "Identical vendor, amount, date and employee"
    });

    // mark original also
    duplicatesMap.set(originalId, {
      is_duplicate: true,
      related_duplicate: tx.transaction_id
    });

  } else {
    seen.set(fingerprint, tx.transaction_id);
  }
});

// ── 2. Category budget totals ────────────────────────────────────
const budgetLimits = {
  "Cloud Infrastructure": 10000,
  "Travel": 5000,
  "Meals & Entertainment": 2000,
  "Software": 3000,
  "Office Supplies": 1000,
  "Marketing": 8000
};

const categoryTotals = {};
transactions.forEach(tx => {
  categoryTotals[tx.category] = (categoryTotals[tx.category] || 0) + Number(tx.amount);
});

// mark which categories are over budget
const overBudgetCategories = new Set(
  Object.entries(categoryTotals)
    .filter(([cat, total]) => budgetLimits[cat] && total > budgetLimits[cat])
    .map(([cat]) => cat)
);

// ── 3. Policy violation checks ───────────────────────────────────
const ROUND_NUMBER_THRESHOLD = 5000;
const WEEKEND_CATEGORIES_ALLOWED = ["Travel"];
const HIGH_VALUE_THRESHOLD = 10000;

// ── 4. Return per-transaction enriched output ─────────────────────
return transactions.map(tx => {

  const txDate = new Date(tx.date);
  const dayOfWeek = txDate.getDay();
  const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
  const amount = Number(tx.amount);

  const violations = [];

  if (isWeekend && !WEEKEND_CATEGORIES_ALLOWED.includes(tx.category)) {
    violations.push("weekend_transaction");
  }

  if (amount >= ROUND_NUMBER_THRESHOLD && amount % 1000 === 0) {
    violations.push("suspicious_round_number");
  }

  if (amount > HIGH_VALUE_THRESHOLD) {
    violations.push("high_value");
  }

  return {
    json: {
      ...tx,

      // 🔁 Duplicate info
      duplicate_info: duplicatesMap.get(tx.transaction_id) || {
        is_duplicate: false
      },

      // 💰 Budget info
      category_total: categoryTotals[tx.category] || 0,
      category_budget: budgetLimits[tx.category] || null,
      is_over_budget: overBudgetCategories.has(tx.category),

      // 🚨 Policy flags
      violations,
      violation_count: violations.length,

      // 🧠 Useful flags
      is_weekend: isWeekend,
      is_high_risk: violations.length > 0 || duplicatesMap.has(tx.transaction_id),

      // 📊 Global context (optional but powerful)
      total_transactions: transactions.length,
      total_spend: transactions.reduce((s, t) => s + Number(t.amount), 0),

      processed_at: new Date().toISOString()
    }
  };
});

const items = $input.all();

let allAnomalies = [];
let summaries = [];

for (const item of items) {

  let content = item.json.output || "";

  // 🧹 Clean markdown fences
  content = content.replace(/```json|```/g, '').trim();

  if (!content) continue;

  let parsed;

  try {
    parsed = JSON.parse(content);
  } catch (e) {
    // skip bad JSON but keep debugging option
    continue;
  }

  // ✅ Normalize anomalies
  if (Array.isArray(parsed.anomalies)) {
    parsed.anomalies.forEach(a => {

      allAnomalies.push({
        ...a,

        // 🔧 Normalize fields
        severity: (a.severity || "low").toLowerCase(),
        anomaly_type: (a.anomaly_type || "").toLowerCase(),

        // 🧠 Enrichment
        detected_at: new Date().toISOString(),
        workflow_run_id: $execution.id,
        status: "open",

        fraud_score: a.fraud_score ?? 0,
        confidence: a.confidence ?? 0,
        amount: Number(a.amount || 0),

        // 🚀 Flags
        is_high_risk: (a.severity || "").toLowerCase() === "high" || (a.fraud_score ?? 0) >= 80,
        needs_review: (a.severity || "").toLowerCase() !== "low"
      });

    });
  }

  // collect summaries
  if (parsed.summary) {
    summaries.push(parsed.summary);
  }
}

// ── 📊 Aggregate summary ─────────────────────────────
const summary = {
  total_anomalies: allAnomalies.length,
  high: allAnomalies.filter(a => a.severity === "high").length,
  medium: allAnomalies.filter(a => a.severity === "medium").length,
  low: allAnomalies.filter(a => a.severity === "low").length,
  total_suspicious_amount: allAnomalies.reduce((s, a) => s + a.amount, 0),
};

// ── 🔁 RETURN MULTIPLE ITEMS (KEY CHANGE) ────────────

// 1. Return each anomaly as separate item
const anomalyItems = allAnomalies.map(a => ({
  json: {
    type: "anomaly",
    ...a
  }
}));

// 2. Add ONE summary item (optional but powerful)
const summaryItem = {
  json: {
    type: "summary",
    ...summary
  }
};

return [...anomalyItems, summaryItem];

